#include <vector>
#include <algorithm>

using namespace std;

vector<vector<long long>> solve(vector<vector<long long>> grid, long long x, long long y, long long k) {
    int m = grid.size();
    int n = grid[0].size();

    vector<vector<long long>> submatrix;
    for (long long i = x; i < x + k; ++i) {
        vector<long long> row;
        for (long long j = y; j < y + k; ++j) {
            row.push_back(grid[i][j]);
        }
        submatrix.push_back(row);
    }

    reverse(submatrix.begin(), submatrix.end());

    for (long long i = 0; i < k; ++i) {
        long long original_row = x + i;
        vector<long long> new_row = submatrix[i];
        for (long long j = 0; j < k; ++j) {
            grid[original_row][y + j] = new_row[j];
        }
    }

    return grid;
}

