import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

public class Solution {
    public static long[][] solve(long[][] grid, long x, long y, long k) {
        int m = grid.length;
        int n = grid[0].length;

        List<List<Long>> submatrix = new ArrayList<>();
        for (int i = 0; i < k; i++) {
            List<Long> row = new ArrayList<>();
            for (int j = 0; j < k; j++) {
                row.add(grid[(int)x + i][ (int)y + j]);
            }
            submatrix.add(row);
        }

        Collections.reverse(submatrix);

        for (int i = 0; i < k; i++) {
            List<Long> row = submatrix.get(i);
            for (int j = 0; j < k; j++) {
                grid[(int)x + i][ (int)y + j] = row.get(j);
            }
        }

        return grid;
    }
}
